CREATE OR REPLACE FUNCTION rda.approval_check_state(_order_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
    DECLARE
        _max_level integer;
        _max_state varchar;
        _actual_state varchar;
        _actual_level integer;
        _next_state varchar;
        _next_level integer;
        _rejected_exists boolean := false;
        _approved_exists boolean :=false;
        _global_state varchar := '';
    BEGIN

    SELECT MAX(level) INTO _max_level
        FROM rda.approval
        WHERE order_id = _order_id;


    SELECT state INTO _max_state
        FROM rda.approval
        WHERE level = _max_level AND order_id = _order_id;


    SELECT state, level INTO _actual_state, _actual_level
        FROM rda.approval
        WHERE state IN ('APPROVED', 'REJECTED') AND order_id = _order_id
        ORDER BY level ASC
            LIMIT 1;

    --check per vedere se il livello è max
    IF _actual_level = _max_level THEN
        _next_state := NULL;
        _next_level := NULL;

    ELSE
        SELECT state, level INTO _next_state, _next_level
        FROM rda.approval
        WHERE order_id = _order_id AND level = (_actual_level + 1)
    ORDER BY level ASC
        LIMIT 1;
    END IF;

    -- check per rejected
    SELECT EXISTS(
        SELECT 1
        FROM rda.approval
        WHERE order_id = _order_id AND state = 'REJECTED'
    ) INTO _rejected_exists;

    SELECT EXISTS(
        SELECT 1
        FROM rda.approval
        WHERE order_id = _order_id AND state = 'APPROVED' AND level=_max_level
    ) INTO _approved_exists;


    -- set rejected variable
    IF _rejected_exists THEN
        _global_state := 'REJECTED';
    END IF;

    IF _approved_exists THEN
        _global_state := 'APPROVED';
    END IF;

    RETURN jsonb_build_object(
        'order_id', _order_id,
        'max_approval_level', jsonb_build_object(
            'level', _max_level,
            'state', _max_state
        ),
        'actual_approval_level', jsonb_build_object(
            'level', _actual_level,
            'state', _actual_state
        ),
        'next_approval_level', jsonb_build_object(
            'level', _next_level,
            'state', _next_state
        ),
        'global_state', _global_state
    );
    END;
$function$

CREATE OR REPLACE FUNCTION rda.insert_approval_rule(_payload jsonb)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _order_id    BIGINT;
    _approver_id BIGINT;
    _level       INT;
BEGIN
    -- extract fields from JSON
    _order_id    := (_payload ->> 'order_id')::BIGINT;
    _approver_id := (_payload ->> 'approver_id')::BIGINT;
    _level       := (_payload ->> 'level')::INT;

    -- basic validation
    IF _order_id IS NULL OR _approver_id IS NULL OR _level IS NULL THEN
        RAISE EXCEPTION 'invalid approval rule payload'
            USING ERRCODE = 'T1WZ4';
    END IF;

    -- ensure purchase order exists
    IF NOT EXISTS (
        SELECT 1
        FROM rda.purchase_order
        WHERE id = _order_id
          AND deleted IS NULL
    ) THEN
        RAISE EXCEPTION 'purchase order not found'
            USING ERRCODE = 'T0WZ0';
    END IF;

    -- insert rule (ignore if already exists)
    INSERT INTO rda.approval (
        order_id,
        approver_id,
        level,
        created,
        state
    )
    VALUES (
               _order_id,
               _approver_id,
               _level,
               NOW(),
            'PENDING'
           )
    ON CONFLICT ON CONSTRAINT approval_unique_rule DO NOTHING;

END;
$function$

CREATE OR REPLACE FUNCTION rda.notification_new(_json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
BEGIN

    INSERT INTO rda.notification(type, user_id, order_id) VALUES (
     _json_data->>'type',
    (_json_data->>'user_id')::bigint,
    (_json_data->>'order_id')::bigint
    ) RETURNING id into _id;

    RETURN to_jsonb(_id);
END;
$function$

CREATE OR REPLACE FUNCTION rda.po_accept_budget_increment(_order_id bigint, _user_email character varying, _increment_promise numeric)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user json;
BEGIN

    ----------------------------------------
    -- VALIDATION
    ----------------------------------------

    -- check if PO exists
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND deleted IS NULL) THEN
        RAISE EXCEPTION '[po_accept_budget_increment] PO with id % not found', _order_id USING ERRCODE = 'T0WZ0';
    end if;

    -- check if PO is in state PENDING_BUDGET_INCREMENT
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND state = 'PENDING_BUDGET_INCREMENT') THEN
        RAISE EXCEPTION '[po_accept_budget_increment] PO with id % is not in PENDING_BUDGET_INCREMENT state', _order_id USING ERRCODE = 'T0WZ3';
    end if;

    -- check if user exists and is enabled
    _user := users_int.user_get_by_email(_user_email, TRUE);

    -- check if user has permission
    IF NOT EXISTS (SELECT * FROM users_int."user" u INNER JOIN users_int.role r ON u.role = r.name WHERE u.id = (_user->>'id')::bigint AND r.is_approver_extra_budget) THEN
        RAISE EXCEPTION '[po_accept_budget_increment] User with id % cannot manage budget increments', (_user->>'id')::bigint USING ERRCODE = 'T0WZ2';
    end if;

    ----------------------------------------
    -- Update state to "PENDING_BUDGET_SUBTRACTION" (ACQUIRE LOCK) -> if fails LockAcquisitionFailed
    ----------------------------------------

    INSERT INTO rda.purchase_order_history(order_id, user_id, prev_state, next_state, description) VALUES (_order_id, (_user->>'id')::bigint, 'PENDING_BUDGET_INCREMENT',  'PENDING_BUDGET_SUBTRACTION', 'Ha approvato la richiesta di aumento budget');
    INSERT INTO rda.extra_budget_approval(order_id, increment_promise, approver_id) VALUES (_order_id, _increment_promise, (_user->>'id')::bigint);
    UPDATE rda.purchase_order SET state = 'PENDING_BUDGET_SUBTRACTION', updated = NOW() WHERE id = _order_id;

EXCEPTION
    WHEN unique_violation THEN
        -- lock acquisition failed (another order already in that state)
        RAISE EXCEPTION 'LockAcquisitionFailed: another purchase_order is already in PENDING_BUDGET_SUBTRACTION'
            USING ERRCODE = 'T0WZ5';

END;
$function$

CREATE OR REPLACE FUNCTION rda.po_check_payment_method_available(_po_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_payment_code char(6);
    v_rda_available boolean;
    v_provider_default_payment char(6);
BEGIN
    -- Load payment method and provider default payment method
    SELECT po.payment_method, p.default_payment_method
    INTO v_payment_code, v_provider_default_payment
    FROM rda.purchase_order po
             JOIN provider_qualifications.provider p
                  ON p.id = po.provider_id
    WHERE po.id = _po_id;

    IF v_payment_code IS NULL THEN
        RAISE EXCEPTION 'PO not found or payment method not set' USING ERRCODE = 'T0WZ3';
    END IF;

    -- Check payment method availability
    SELECT rda_available
    INTO v_rda_available
    FROM provider_qualifications.payment_method
    WHERE code = v_payment_code;

    IF v_rda_available IS NULL THEN
        RETURN FALSE;
    END IF;

    -- If RDA available, OK
    IF v_rda_available THEN
        RETURN TRUE;
    END IF;

    -- If not RDA available, allow only if it matches provider default
    IF TRIM(v_payment_code) = TRIM(v_provider_default_payment) THEN
        RETURN TRUE;
    END IF;

    RETURN FALSE;
END;
$function$

CREATE OR REPLACE FUNCTION rda.po_check_quotes_threshold(_po_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_total numeric;
    v_doc_threshold numeric;
    v_min_quotes integer;
    v_quote_count integer;
BEGIN
    -- Load PO total
    SELECT total_price
    INTO v_total
    FROM rda.purchase_order
    WHERE id = _po_id;

    IF v_total IS NULL THEN
        RAISE EXCEPTION 'PO not found';
    END IF;

    -- Load DOCUMENT_CHECK_THRESHOLD
    SELECT threshold_value
    INTO v_doc_threshold
    FROM rda.purchase_order_threshold
    WHERE threshold_name = 'DOCUMENT_CHECK_THRESHOLD';

    -- Load DOCUMENT_CHECK_MIN_ATTACHMENT
    SELECT threshold_value::integer
    INTO v_min_quotes
    FROM rda.purchase_order_threshold
    WHERE threshold_name = 'DOCUMENT_CHECK_MIN_ATTACHMENT';

    -- If PO total < threshold, no check needed
    IF v_total < v_doc_threshold THEN
        RETURN TRUE;
    END IF;

    -- Count active QUOTE attachments
    SELECT COUNT(*)
    INTO v_quote_count
    FROM rda.purchase_order_attachment a
    WHERE a.order_id = _po_id
      AND a.attachment_type = 'quote'
      AND a.deleted IS NULL;

    IF v_quote_count >= v_min_quotes THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION rda.po_provider_activated(_provider_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _record record;
BEGIN

    -- for each po that is in 'PENDING_APPROVAL_PROVIDER' state and has provider_id = _provider_id
    FOR _record IN (SELECT * FROM rda.purchase_order WHERE provider_id = _provider_id AND state = 'PENDING_APPROVAL_PROVIDER')
    LOOP

        -- check if state can be updated
        IF rda.po_check_provider_approval(_record.id) THEN

            -- log
            INSERT INTO rda.purchase_order_history(order_id, automatic, prev_state, next_state, description) VALUES (_record.id, TRUE, _record.state,  'PENDING_APPROVAL_PAYMENT_METHOD', 'Il fornitore è stato qualificato');

            -- set state = 'PENDING_APPROVAL_PAYMENT_METHOD'
            UPDATE rda.purchase_order SET state = 'PENDING_APPROVAL_PAYMENT_METHOD' WHERE id = _record.id;
        END IF;
    end loop;
END;
$function$

CREATE OR REPLACE FUNCTION rda.po_provider_deactivated(_provider_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE _po record;
BEGIN
    FOR _po IN SELECT po.* FROM rda.purchase_order po JOIN rda.purchase_order_state s ON po.state = s.name WHERE po.provider_id = _provider_id AND s.final = FALSE
        LOOP
            IF NOT rda.po_check_provider_approval(_po.id) THEN
                INSERT INTO rda.purchase_order_history(order_id, automatic, prev_state, next_state, description)
                VALUES (_po.id, TRUE, _po.state, 'PENDING_APPROVAL_PROVIDER', 'Il fornitore non è più qualificato');
                UPDATE rda.purchase_order SET state = 'PENDING_APPROVAL_PROVIDER' WHERE id = _po.id;
            END IF;
        END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION rda.po_reject_budget_increment(_order_id bigint, _user_email character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user json;
BEGIN

    -- check if PO exists
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND deleted IS NULL) THEN
        RAISE EXCEPTION '[po_reject_budget_increment] PO with id % not found', _order_id USING ERRCODE = 'T0WZ0';
    end if;

    -- check if PO is in state PENDING_BUDGET_INCREMENT
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND state = 'PENDING_BUDGET_INCREMENT') THEN
        RAISE EXCEPTION '[po_reject_budget_increment] PO with id % is not in PENDING_BUDGET_INCREMENT state', _order_id USING ERRCODE = 'T0WZ3';
    end if;

    -- check if user exists and is enabled
    _user := users_int.user_get_by_email(_user_email, TRUE);

    -- check if user has permission
    IF NOT EXISTS (SELECT * FROM users_int."user" u INNER JOIN users_int.role r ON u.role = r.name WHERE u.id = (_user->>'id')::bigint AND r.is_approver_extra_budget) THEN
        RAISE EXCEPTION '[po_reject_budget_increment] User with id % cannot manage budget increments', (_user->>'id')::bigint USING ERRCODE = 'T0WZ2';
    end if;

    -- set state to rejected
    INSERT INTO rda.purchase_order_history(order_id, user_id, prev_state, next_state, description) VALUES (_order_id, (_user->>'id')::bigint, 'PENDING_BUDGET_INCREMENT',  'REJECTED', 'Ha rigettato la richiesta di aumento budget');
    UPDATE rda.purchase_order SET state = 'REJECTED', updated = NOW() WHERE id = _order_id;

END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_approve_or_reject_leasing(p_order_id bigint, p_user_id bigint, p_approve boolean, p_without_leasing boolean DEFAULT false)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_po_state varchar;
    v_new_state varchar;
    v_description text;
    v_leasing boolean;
BEGIN
    -- AFC authorization
    IF NOT EXISTS (
        SELECT 1
        FROM users_int.user u
                 JOIN users_int.role r ON r.name = u.role
        WHERE u.id = p_user_id
          AND r.is_afc = true
    ) THEN
        RAISE EXCEPTION 'unauthorized'
            USING ERRCODE = 'T0WZ2';
    END IF;

    -- Fetch current PO state
    SELECT state
    INTO v_po_state
    FROM rda.purchase_order
    WHERE id = p_order_id;

    IF v_po_state IS NULL OR v_po_state <> 'PENDING_LEASING' THEN
        RAISE EXCEPTION 'invalid state'
            USING ERRCODE = 'T0WZ3';
    END IF;

    -- Decision matrix
    IF p_approve AND p_without_leasing THEN
        v_new_state := 'PENDING_CONTRACT_VERIFICATION';
        v_description := 'Approved without leasing by AFC';
        v_leasing := false;

    ELSIF p_approve THEN
        v_new_state := 'PENDING_CONTRACT_VERIFICATION';
        v_description := 'Leasing approved by AFC';
        v_leasing := true;

    ELSE
        v_new_state := 'PENDING_APPROVAL_NO_LEASING';
        v_description := 'Leasing rejected by AFC';
        v_leasing := false;
    END IF;

    UPDATE rda.purchase_order
    SET state   = v_new_state,
        leasing = v_leasing,
        updated = now()
    WHERE id = p_order_id;

    INSERT INTO rda.purchase_order_history (
        order_id,
        user_id,
        description,
        prev_state,
        next_state,
        automatic
    ) VALUES (
                 p_order_id,
                 p_user_id,
                 v_description,
                 v_po_state,
                 v_new_state,
                 false
             );
END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_approve_payment_method(_po_id bigint, _user_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _owner_id BIGINT;
    _state VARCHAR;
    _payment_method CHAR(6);
    _provider_id BIGINT;
BEGIN
    -- get PO owner, state, payment method
    SELECT requester_id, state, payment_method, provider_id
    INTO _owner_id, _state, _payment_method, _provider_id
    FROM rda.purchase_order
    WHERE id = _po_id
      AND deleted IS NULL;

    -- check if po exists
    IF NOT FOUND THEN
        RAISE EXCEPTION 'purchase order not found' USING ERRCODE = 'T0WZ0';
    END IF;

    -- check state valid
    IF _state <> 'PENDING_APPROVAL_PAYMENT_METHOD' THEN
        RAISE EXCEPTION 'purchase order is not in a state to approve payment method'
            USING ERRCODE = 'T0WZ3';
    END IF;

    -- ensure payment method is set
    IF _payment_method IS NULL THEN
        RAISE EXCEPTION 'payment method not set' USING ERRCODE = 'T8QZ4';
    END IF;

    -- set default payment method for the provider if not already set
    PERFORM provider_qualifications.set_default_payment_method(
            _provider_id,
            _payment_method
            );

    ----------------------------------------
    -- history + state transition
    ----------------------------------------
    INSERT INTO rda.purchase_order_history (
        order_id,
        automatic,
        user_id,
        prev_state,
        next_state,
        description
    )
    VALUES (
               _po_id,
               FALSE,
                _user_id,
               'PENDING_APPROVAL_PAYMENT_METHOD',
               'PENDING_APPROVAL',
               'Payment method approved'
           );

    UPDATE rda.purchase_order
    SET state = 'PENDING_APPROVAL',
        updated = NOW()
    WHERE id = _po_id;

END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_comment_get_all(_filter_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _filter_struct ->> 'search_string', '%') INTO _search_pattern;

    RETURN COALESCE(
        (
            SELECT jsonb_agg(x)
            FROM (
                SELECT c.*, users_int.user_get(c.user_id) as user
                FROM rda.purchase_order_comment c
                WHERE c.comment LIKE _search_pattern
                AND ( _filter_struct ->> 'po_id' IS NULL OR c.order_id = (_filter_struct ->> 'po_id')::bigint)
                ORDER BY c.timestamp DESC
            )x
        ),
        '[]'::jsonb
    );

END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_comment_new(_json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _po_id bigint;
    _user_id bigint;
    _id bigint;
BEGIN

    _po_id := (_json_data->>'order_id')::bigint;
    _user_id := (_json_data->>'user_id')::bigint;

    -- check user exists
    IF NOT EXISTS (SELECT * FROM users_int."user" WHERE id = _user_id) THEN
        RAISE EXCEPTION '[purchase_order_comment_new] User with id % not found', _user_id USING ERRCODE = 'T0JZ0';
    end if;

    -- check if PO exists
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _po_id) THEN
        RAISE EXCEPTION '[purchase_order_comment_new] PO with id % not found', _po_id USING ERRCODE = 'T0WZ0';
    end if;

    -- create entry
    INSERT INTO rda.purchase_order_comment (
        user_id,
        order_id,
        comment
    ) VALUES (
        _user_id,
        _po_id,
        _json_data->>'comment'
    ) RETURNING id INTO _id;

    RETURN to_jsonb(_id);

END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_delete(_order_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
    BEGIN

        IF NOT EXISTS (SELECT 1 FROM rda.purchase_order WHERE id = _order_id AND deleted IS NULL) THEN
            RAISE EXCEPTION 'Document ID % does not exist.', _order_id USING ERRCODE = 'T0WZ0';
        end if;
        IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND state = 'DRAFT') THEN
            RAISE EXCEPTION '[purchase_order_edit] PO with id % is not in DRAFT state', _order_id USING ERRCODE = 'T0WZ3';
        end if;

        UPDATE rda.purchase_order SET deleted=NOW(), state='CANCELED' WHERE id=_order_id;
    END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_edit___back(_json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _order_id bigint;
BEGIN
    _order_id := (_json_data ->> 'id')::bigint;

    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND deleted IS NULL) THEN
        RAISE EXCEPTION '[purchase_order_edit] PO with id % not found', _order_id USING ERRCODE = 'T0WZ0';
    end if;

    -- check if editable
    IF NOT EXISTS (SELECT * FROM rda.purchase_order WHERE id = _order_id AND state = 'DRAFT') THEN
        RAISE EXCEPTION '[purchase_order_edit] PO with id % is not in DRAFT state', _order_id USING ERRCODE = 'T0WZ3';
    end if;


    -- update table
    IF _json_data->>'type' IS NOT NULL THEN
        UPDATE rda.purchase_order SET type = _json_data->>'type' WHERE id = _order_id;
    end if;

    IF _json_data->>'requester_id' IS NOT NULL THEN
        UPDATE rda.purchase_order SET requester_id = (_json_data->>'requester_id')::bigint WHERE id = _order_id;
    end if;

    IF _json_data->>'reference_warehouse' IS NOT NULL THEN
        UPDATE rda.purchase_order SET reference_warehouse = _json_data->>'reference_warehouse' WHERE id = _order_id;
    end if;

    IF _json_data->>'payment_method' IS NOT NULL THEN
        UPDATE rda.purchase_order SET payment_method = _json_data->>'payment_method' WHERE id = _order_id;
    end if;

    IF _json_data->>'budget_id' IS NOT NULL THEN
        UPDATE rda.purchase_order SET budget_id = (_json_data->>'budget_id')::bigint WHERE id = _order_id;
    end if;

    IF _json_data->>'budget_user_id' IS NOT NULL THEN
        UPDATE rda.purchase_order SET budget_user_id = (_json_data->>'budget_user_id')::bigint WHERE id = _order_id;
    end if;

    IF _json_data->>'cost_center' IS NOT NULL THEN
        UPDATE rda.purchase_order SET cost_center = _json_data->>'cost_center' WHERE id = _order_id;
    end if;

    IF _json_data->>'provider_id' IS NOT NULL THEN
        UPDATE rda.purchase_order SET provider_id = (_json_data->>'provider_id')::bigint WHERE id = _order_id;
    end if;

    IF _json_data->>'project' IS NOT NULL THEN
        UPDATE rda.purchase_order SET project = _json_data->>'project' WHERE id = _order_id;
    end if;

    IF _json_data->>'description' IS NOT NULL THEN
        UPDATE rda.purchase_order SET description = _json_data->>'description' WHERE id = _order_id;
    end if;

    IF _json_data->>'currency' IS NOT NULL THEN
        UPDATE rda.purchase_order SET currency = _json_data->>'currency' WHERE id = _order_id;
    end if;

    IF _json_data->>'state' IS NOT NULL THEN
        UPDATE rda.purchase_order SET state = _json_data->>'state' WHERE id = _order_id;
    end if;

    UPDATE rda.purchase_order SET updated = NOW() WHERE id = _order_id;
END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_edit_payment_method(_po_id bigint, _payment_method character, _user_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _owner_id BIGINT;
    _state VARCHAR;
BEGIN
    -- get PO owner and state, check it exists (not deleted)
    SELECT requester_id, state
    INTO _owner_id, _state
    FROM rda.purchase_order
    WHERE id = _po_id
      AND deleted IS NULL;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'purchase order not found' USING ERRCODE = 'T0WZ0';
    END IF;

    -- check ownership
    IF _owner_id <> _user_id THEN
        RAISE EXCEPTION 'user is not the owner of the purchase order' USING ERRCODE = 'T0WZ1';
    END IF;

    -- check state
    IF _state <> 'PENDING_APPROVAL_PAYMENT_METHOD' THEN
        RAISE EXCEPTION 'purchase order is not in a state to edit payment method' USING ERRCODE = 'T0WZ3';
    END IF;

    -- validate payment method exists and is enabled
    IF NOT EXISTS (
        SELECT 1
        FROM provider_qualifications.payment_method
        WHERE code = _payment_method
          AND rda_available = true
    ) THEN
        RAISE EXCEPTION 'invalid payment method' USING ERRCODE = 'T8QZ3';
    END IF;

    -- update payment method
    UPDATE rda.purchase_order
    SET payment_method = _payment_method,
        updated = now()
    WHERE id = _po_id;

END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_index_paginated(_disable_pagination boolean, _actual_page integer, _results_for_page integer)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    _offset       int;
    _total_pages  bigint;
    _total_items  bigint;
    _query        text;
    _items        jsonb;
BEGIN
    -- def
    _disable_pagination := COALESCE(_disable_pagination, false);
    _actual_page := COALESCE(NULLIF(_actual_page, 0), 1);
    _results_for_page := COALESCE(NULLIF(_results_for_page, 0), 10);

    _offset := (_actual_page - 1) * _results_for_page;

    -- totali
    EXECUTE 'SELECT COUNT(*) FROM rda.purchase_order'
    INTO _total_items;

    _total_pages := CEIL(_total_items::DECIMAL / _results_for_page);
    -- se non c'è paginazione
    IF _disable_pagination THEN
        _query := 'SELECT jsonb_agg(t) FROM (SELECT * FROM rda.purchase_order) t';
    ELSE
    --se c'è paginazione
        _query := format(
            'SELECT jsonb_agg(t) FROM (SELECT * FROM rda.purchase_order LIMIT %s OFFSET %s) t',
            _results_for_page,
            _offset
        );
    END IF;

    EXECUTE _query INTO _items;

    RETURN jsonb_build_object(
        'items', COALESCE(_items, '[]'::jsonb),
        'total_items', _total_items,
        'total_pages', _total_pages,
        'current_page', _actual_page
    );
END;
$function$

CREATE OR REPLACE FUNCTION rda.purchase_order_row_delete(_po_id bigint, _row_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
    BEGIN
       IF EXISTS(SELECT 1 FROM rda.purchase_order as po, rda.purchase_order_row as porow WHERE porow.id=_row_id AND po.id=porow.order_id AND po.state <> 'DRAFT') THEN
            RAISE EXCEPTION 'Document ID % is not editable. The order state is not "draft" state', _po_id
            USING ERRCODE = 'T0WZ3';
        END IF;
        IF NOT EXISTS(SELECT 1 FROM rda.purchase_order as po, rda.purchase_order_row as porow WHERE porow.id=_row_id AND porow.order_id=_po_id) THEN
            RAISE EXCEPTION 'Row Id % is not presnet in Document Id %', _row_id,  _po_id
            USING ERRCODE = 'T0WZ3';
        END IF;
        DELETE FROM rda.purchase_order_row WHERE id=_row_id;
    END;

$function$

CREATE OR REPLACE FUNCTION rda.trg_check_document_on_state_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_quote_count integer;
    v_min_attachment integer;
    _prev_state varchar;
BEGIN
    IF OLD.state IS DISTINCT FROM NEW.state
        AND NEW.state = 'PENDING_CHECK_DOCUMENT' THEN

        _prev_state := NEW.state;

        SELECT threshold_value::integer
        INTO v_min_attachment
        FROM rda.purchase_order_threshold
        WHERE threshold_name = 'DOCUMENT_CHECK_MIN_ATTACHMENT';

        IF v_min_attachment IS NULL THEN
            RAISE EXCEPTION 'DOCUMENT_CHECK_MIN_ATTACHMENT threshold not configured'
                USING ERRCODE = 'T0WZ3';
        END IF;

        SELECT COUNT(*)
        INTO v_quote_count
        FROM rda.purchase_order_attachment a
        WHERE a.order_id = NEW.id
          AND a.attachment_type = 'quote'
          AND a.deleted IS NULL;

        IF v_quote_count >= v_min_attachment THEN

            INSERT INTO rda.purchase_order_history(
                order_id, user_id, description, prev_state, next_state, automatic
            )
            VALUES (
                       NEW.id,
                       NULL,
                       'PO automatically moved from PENDING_CHECK_DOCUMENT to PENDING_APPROVAL_PROVIDER (≥ '
                           || v_min_attachment || ' QUOTE attachments)',
                       _prev_state,
                       'PENDING_APPROVAL_PROVIDER',
                       TRUE
            );

            UPDATE rda.purchase_order SET state = 'PENDING_APPROVAL_PROVIDER', updated = now() WHERE id = NEW.id;
        END IF;

    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION rda.trg_po_submitted_threshold()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _threshold NUMERIC;
    _prev_state varchar;
    _next_state varchar;
BEGIN
    IF OLD.state IS DISTINCT FROM NEW.state
        AND NEW.state = 'SUBMITTED'
    THEN
        _prev_state := NEW.state;

        SELECT threshold_value
        INTO _threshold
        FROM rda.purchase_order_threshold
        WHERE threshold_name = 'DOCUMENT_CHECK_THRESHOLD';

        IF _threshold IS NULL THEN
            RAISE EXCEPTION
                'DOCUMENT_CHECK_THRESHOLD not configured'
                USING ERRCODE = 'T8JZ3';
        END IF;

        IF NEW.total_price >= _threshold THEN
--             _next_state := 'PENDING_CHECK_DOCUMENT';
            NEW.state := 'PENDING_CHECK_DOCUMENT';
        ELSE
--             _next_state := 'PENDING_APPROVAL_PROVIDER';
            NEW.state := 'PENDING_APPROVAL_PROVIDER';
        END IF;

        -- add history
        INSERT INTO rda.purchase_order_history(
            order_id, user_id, description, prev_state, next_state, automatic
        )
        VALUES (
                   NEW.id,
                   NULL,
                   'PO submitted, automatically moved to ' || NEW.state,
                   _prev_state,
                   _next_state,
                   TRUE
        );

        -- update state
--         UPDATE rda.purchase_order SET state = _next_state, updated = NOW() WHERE id = NEW.id;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION rda.trg_provider_category_state_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _old_usable BOOLEAN;
    _new_usable BOOLEAN;
BEGIN
    -- only if state actually changed
    IF OLD.state IS DISTINCT FROM NEW.state THEN

        SELECT usable
        INTO _old_usable
        FROM provider_qualifications.provider_category_state
        WHERE name = OLD.state;

        SELECT usable
        INTO _new_usable
        FROM provider_qualifications.provider_category_state
        WHERE name = NEW.state;

        -- !usable → usable
        IF _new_usable = TRUE
            AND COALESCE(_old_usable, FALSE) = FALSE THEN
            PERFORM rda.po_provider_activated(NEW.provider_id);

        -- usable → !usable
        ELSIF _new_usable = FALSE
            AND COALESCE(_old_usable, FALSE) = TRUE THEN
            PERFORM rda.po_provider_deactivated(NEW.provider_id);

        END IF;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION rda.trg_provider_state_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
