CREATE OR REPLACE FUNCTION rda.trg_subtract_po_from_budget()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _total numeric(20, 5);
BEGIN
    IF NEW.subtracted_from_budget <> OLD.subtracted_from_budget THEN

        _total := NEW.total_price;

        IF NEW.subtracted_from_budget THEN

            -- add total to used
            IF NEW.cost_center IS NOT NULL THEN

                -- this PO is tied to a cost center
                UPDATE budgets.cost_center_budget SET current = current + _total WHERE cost_center = NEW.cost_center AND budget_id = NEW.budget_id;
            ELSE

                -- this PO is tied to user
                UPDATE budgets.user_budget SET current = current + _total WHERE user_id = NEW.budget_user_id AND budget_id = NEW.budget_id;
            END IF;
        ELSE

            -- subtract total from used
            IF NEW.cost_center IS NOT NULL THEN

                -- this PO is tied to a cost center
                UPDATE budgets.cost_center_budget SET current = current - _total WHERE cost_center = NEW.cost_center AND budget_id = NEW.budget_id;
            ELSE

                -- this PO is tied to user
                UPDATE budgets.user_budget SET current = current - _total WHERE user_id = NEW.budget_user_id AND budget_id = NEW.budget_id;
            END IF;
        END IF;
    END IF;

    RETURN new;
END;
$function$

