    _increment_needed numeric(20, 5);
BEGIN

    IF NEW.state = 'PENDING_BUDGET_INCREMENT_CHECK' THEN

        _increment_needed := budgets.compute_budget_increment_needed(NEW.budget_id, NEW.cost_center, NEW.budget_user_id, NEW.total_price);

        IF (_increment_needed > 0) THEN

            -- insert log
            INSERT INTO rda.purchase_order_history(order_id, automatic, prev_state, next_state, description) VALUES (NEW.id, TRUE, 'PENDING_BUDGET_INCREMENT_CHECK',  'PENDING_BUDGET_INCREMENT', 'Il po ha bisogno di incremento budget');

            NEW.state := 'PENDING_BUDGET_INCREMENT';

