            -- insert log
            INSERT INTO rda.purchase_order_history(order_id, automatic, prev_state, next_state, description) VALUES (NEW.id, TRUE, 'PENDING_BUDGET_INCREMENT_CHECK',  'PENDING_BUDGET_SUBTRACTION', 'Il po non ha bisogno di incremento budget');

            NEW.state := 'PENDING_BUDGET_SUBTRACTION';
        end if;

    end if;



    RETURN NEW;
