CREATE OR REPLACE FUNCTION rda.trigger_notify_pending_provider_saved_in_alyante()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user record;
    _provider_erp_id text;
BEGIN
    -- Only act when state changes to PENDING_PROVIDER_SAVED_IN_ALYANTE
    IF NEW.state = 'PENDING_PROVIDER_SAVED_IN_ALYANTE'
        AND (OLD.state IS DISTINCT FROM NEW.state) THEN

        -- Get provider erp_id
        SELECT p.erp_id
        INTO _provider_erp_id
        FROM provider_qualifications.provider p
        WHERE p.id = NEW.provider_id;

        -- If provider.erp_id IS NULL → create notification
        IF _provider_erp_id IS NULL THEN

            FOR _user IN (SELECT * FROM users_int."user" u INNER JOIN users_int.role r ON u.role = r.name WHERE r.is_afc IS TRUE AND u.notifications_enabled IS TRUE)
                LOOP
                    INSERT INTO rda.notification(type, user_id, order_id)
                    VALUES ('AFC_MISSING_PROVIDER', _user.id, NEW.id)
                    ON CONFLICT DO NOTHING;
                end loop;
        END IF;

    END IF;

    RETURN NEW;
END;
$function$

