CREATE OR REPLACE FUNCTION rda.trigger_skip_pending_approval_provider_payment_method()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_provider_default_pm text;
    v_cdlan_default_pm text;
    v_provider_qualified boolean;
    v_skip boolean;
BEGIN
    IF NEW.state = 'PENDING_APPROVAL_PAYMENT_METHOD' THEN

        -- Check if provider is qualified or skip_qualification_validation is enabled
        SELECT p.skip_qualification_validation
        INTO v_skip
        FROM provider_qualifications.provider p
        WHERE p.id = NEW.provider_id;

        v_provider_qualified := rda.po_check_provider_approval(NEW.id) OR v_skip;

        -- Only proceed if provider is qualified
        IF v_provider_qualified THEN

            SELECT p.default_payment_method::text
            INTO v_provider_default_pm
            FROM provider_qualifications.provider p
            WHERE p.id = NEW.provider_id;

            SELECT payment_method_code::text
            INTO v_cdlan_default_pm
            FROM provider_qualifications.payment_method_default_cdlan
            LIMIT 1;

            IF (v_provider_default_pm IS NOT NULL AND trim(v_provider_default_pm) = trim(NEW.payment_method))
                OR (v_cdlan_default_pm IS NOT NULL AND trim(v_cdlan_default_pm) = trim(NEW.payment_method)) THEN
                    NEW.state := 'PENDING_APPROVAL';

                INSERT INTO rda.purchase_order_history (
                    order_id,
                    automatic,
                    prev_state,
                    next_state,
                    description
                ) VALUES (
                             NEW.id,
                             TRUE,
                             'PENDING_APPROVAL_PAYMENT_METHOD',
                             'PENDING_APPROVAL',
                             'Metodo di pagamento già valido per il fornitore'
                         );
            END IF;
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

