CREATE OR REPLACE FUNCTION rda.trigger_subtract_budget()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _eb_approval record;
    _increment_needed numeric(20, 5);
    _increment_id bigint;
BEGIN

    IF NEW.state = 'PENDING_BUDGET_SUBTRACTION' THEN


        ----------------------------------------
        -- Compute budget increment needed
        ----------------------------------------

        _increment_needed := budgets.compute_budget_increment_needed(NEW.budget_id, NEW.cost_center, NEW.budget_user_id, NEW.total_price);

        ----------------------------------------
        -- Apply budget increase if needed
        ----------------------------------------

        IF (_increment_needed > 0) THEN

            SELECT * FROM rda.extra_budget_approval WHERE order_id = NEW.id INTO _eb_approval;

            -- Check if increment needed is equal to increment in input -> if not InvalidInput
            IF (_eb_approval.increment_promise < _increment_needed) THEN
                RAISE EXCEPTION '[trigger_subtract_budget] PO with id % needs % extra budget, but % was approved', NEW.id, _increment_needed, _eb_approval.increment_promise USING ERRCODE = 'T0WZ3';
            end if;

            -- Apply budget increase
            IF NEW.cost_center IS NOT NULL THEN

                -- this PO is tied to a cost center
                INSERT INTO budgets.cost_center_budget_increments(budget_id, cost_center, amount, approver_id) VALUES (NEW.budget_id, NEW.cost_center, _increment_needed, _eb_approval.approver_id) RETURNING id INTO _increment_id;
            ELSE

                -- this PO is tied to user
                INSERT INTO budgets.user_budget_increments(budget_id, user_id, amount, approver_id) VALUES (NEW.budget_id, NEW.budget_user_id, _increment_needed, _eb_approval.approver_id) RETURNING id INTO _increment_id;
            END IF;

            -- save increment id into PO
            NEW.budget_increment_id = _increment_id;
            NEW.updated = now();

            -- log increment successful
            INSERT INTO rda.purchase_order_history(order_id, automatic, user_id, description) VALUES (NEW.id, FALSE, _eb_approval.approver_id, 'Incremento budget completato');
        END IF;

        ----------------------------------------
        -- Add cost of RDA to budget "used" column (trigger)
        ----------------------------------------

        -- sets flags to decrease budget from total
        NEW.subtracted_from_budget := TRUE;
        NEW.updated = now();

        ----------------------------------------
        -- Update state to "PENDING_PROVIDER_SAVED_IN_ALYANTE" (RELEASE LOCK)
        ----------------------------------------

        INSERT INTO rda.purchase_order_history(order_id, automatic, prev_state, next_state, description) VALUES (NEW.id, TRUE, 'PENDING_BUDGET_SUBTRACTION',  'PENDING_PROVIDER_SAVED_IN_ALYANTE', 'PO scalato dal budget');
        NEW.state := 'PENDING_PROVIDER_SAVED_IN_ALYANTE';
        NEW.updated = now();

    end if;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION users_int.role_get_all(_filter_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _filter_struct ->> 'search_string', '%') INTO _search_pattern;

    RETURN COALESCE(
        (
            SELECT jsonb_agg(users_int.role_get(x.name))
            FROM (
                 SELECT r.name
                 FROM users_int.role r
                 WHERE r.name LIKE _search_pattern
                 ORDER BY r.name
             )x
        ),
        '[]'::jsonb
    );

END;
$function$

CREATE OR REPLACE FUNCTION users_int.user_edit(_json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
BEGIN

    SELECT INTO _id (_json_data->>'id')::bigint;

    -- check exists
    IF NOT EXISTS (SELECT * FROM users_int."user" WHERE id = _id) THEN
        RAISE EXCEPTION 'User with id % not found', _id USING ERRCODE = 'T0JZ0';
    end if;

    -- update
    IF _json_data->>'email' IS NOT NULL THEN
        UPDATE users_int."user" SET email = _json_data->>'email', updated_at = now() WHERE id = _id;
    END IF;

    IF _json_data->>'first_name' IS NOT NULL THEN
        UPDATE users_int."user" SET first_name = _json_data->>'first_name', updated_at = now() WHERE id = _id;
    END IF;

    IF _json_data->>'last_name' IS NOT NULL THEN
        UPDATE users_int."user" SET last_name = _json_data->>'last_name', updated_at = now() WHERE id = _id;
    END IF;

    IF _json_data->>'role_name' IS NOT NULL THEN
        UPDATE users_int."user" SET role = _json_data->>'role_name', updated_at = now() WHERE id = _id;
    END IF;

END;
$function$

CREATE OR REPLACE FUNCTION users_int.user_get(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _state json;
    _role json;
BEGIN

    -- check exists
    IF NOT EXISTS (SELECT * FROM users_int."user" WHERE id = _id) THEN
        RAISE EXCEPTION 'User with id % not found', _id USING ERRCODE = 'T0JZ0';
    end if;

    SELECT to_jsonb(x)
    FROM (
        SELECT *
        FROM users_int.user_state
        WHERE name = (SELECT state FROM users_int."user" WHERE id = _id)
    )x
    INTO _state;

    SELECT users_int.role_get((SELECT role FROM users_int."user" WHERE id = _id))
    INTO _role;

    RETURN to_jsonb(x)
    FROM (
        SELECT *, _state as state, _role as role
        FROM users_int."user" u
        WHERE u.id = _id
    )x;

END;
$function$

CREATE OR REPLACE FUNCTION users_int.user_get_by_email(_email character varying, _only_active boolean DEFAULT false)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check exists
    IF NOT EXISTS (SELECT * FROM users_int."user" WHERE email = _email) THEN
        RAISE EXCEPTION 'User with email % not found', _email USING ERRCODE = 'T0JZ0';
    end if;

    IF _only_active AND NOT EXISTS (SELECT * FROM users_int."user" u INNER JOIN users_int.user_state us ON u.state = us.name WHERE u.email = _email AND us.enabled) THEN
        RAISE EXCEPTION 'User with email % is disabled', _email USING ERRCODE = 'T0JZ2';
    end if;

    RETURN users_int.user_get(x.id) FROM (
        SELECT id
        FROM users_int.user
        WHERE email = _email
    )x;

END;
$function$

CREATE OR REPLACE FUNCTION users_int.user_new(_json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
BEGIN

    -- check already exists
    IF EXISTS (SELECT * FROM users_int."user" WHERE email = _json_data ->> 'email') THEN
        RAISE EXCEPTION 'User with email % already exists', _json_data ->> 'email' USING ERRCODE = 'T0JZ1';
