CREATE OR REPLACE FUNCTION budgets.compute_budget_increment_needed(_budget_id bigint, _cost_center character varying, _budget_user_id bigint, _total_price numeric)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    _available_budget numeric(20, 5);
BEGIN

    -- compute available budget
    IF _cost_center IS NOT NULL THEN

        -- this PO is tied to a cost center
        SELECT ("limit" - current) FROM budgets.cost_center_budget WHERE budget_id = _budget_id AND cost_center = _cost_center INTO _available_budget;
    ELSE

        -- this PO is tied to user
        SELECT ("limit" - current) FROM budgets.user_budget WHERE budget_id = _budget_id AND user_id = _budget_user_id INTO _available_budget;
    END IF;

    -- compute actual amount needed for extra budget
    RETURN greatest(0, _total_price - _available_budget);

end;
$function$

