CREATE OR REPLACE FUNCTION budgets.trg_cost_center_budget_increments_propagate()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE budgets.cost_center_budget b
        SET "limit" = b."limit" + NEW.amount
        WHERE b.cost_center = NEW.cost_center
          AND b.budget_id   = NEW.budget_id;

        IF NOT FOUND THEN
            RAISE EXCEPTION
                'No row found in budgets.cost_center_budget for cost_center=% and budget_id=% (INSERT increment id=%)',
                NEW.cost_center, NEW.budget_id, NEW.id;
        END IF;

        RETURN NEW;

    ELSIF TG_OP = 'DELETE' THEN
        UPDATE budgets.cost_center_budget b
        SET "limit" = b."limit" - OLD.amount
        WHERE b.cost_center = OLD.cost_center
          AND b.budget_id   = OLD.budget_id;

        -- no exception on delete if not found bc it could be triggered by a cascade

        RETURN OLD;
    END IF;

    -- Should never happen with the trigger definition
    RAISE EXCEPTION 'Unsupported operation: %', TG_OP;
END;
$function$

