CREATE OR REPLACE FUNCTION provider_qualifications.calculate_provider_qualification(p_provider_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _rec_category RECORD;
    _all_required_docs_count INT;
    _valid_docs_count INT;
    _new_state VARCHAR;
BEGIN
    FOR _rec_category IN
        SELECT pc.id AS provider_category_id, pc.category_id
        FROM provider_qualifications.provider_category pc
        WHERE pc.provider_id = p_provider_id
        LOOP
            SELECT COUNT(*)
            INTO _all_required_docs_count
            FROM provider_qualifications.document_type_category dtc
            WHERE dtc.category_id = _rec_category.category_id
              AND dtc.required = TRUE;

            SELECT COUNT(DISTINCT d.document_type_id)
            INTO _valid_docs_count
            FROM provider_qualifications.document d
                     JOIN provider_qualifications.document_state ds
                          ON ds.name = d.state AND ds.usable = TRUE
                     JOIN provider_qualifications.document_type_category dtc
                          ON dtc.document_type_id = d.document_type_id
                              AND dtc.category_id = _rec_category.category_id
                              AND dtc.required = TRUE
            WHERE d.provider_id = p_provider_id;

            IF _valid_docs_count = _all_required_docs_count THEN
                _new_state := 'QUALIFIED';
            ELSE
                _new_state := 'NOT_QUALIFIED';
            END IF;

            PERFORM provider_qualifications.update_provider_category_state(
                    _rec_category.provider_category_id,
                    _new_state
                    );
        END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.category_new(p_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    new_category_id BIGINT;
    doc JSONB;
BEGIN
    IF NOT (p_json::jsonb ? 'name') OR (p_json::jsonb ->> 'name') = '' THEN
        RAISE EXCEPTION 'Category name (name) is required and cannot be empty'
            USING ERRCODE = 'T3QZ3';
    END IF;

    INSERT INTO provider_qualifications.service_category (name)
    VALUES (p_json::jsonb ->> 'name')
    RETURNING id INTO new_category_id;

    IF p_json::jsonb ? 'document_types'
        AND jsonb_typeof(p_json::jsonb -> 'document_types') = 'array' THEN

        FOR doc IN
            SELECT jsonb_array_elements(p_json::jsonb -> 'document_types')
            LOOP
                IF NOT EXISTS (
                    SELECT 1
                    FROM provider_qualifications.document_type
                    WHERE id = (doc ->> 'id')::BIGINT
                      AND deleted_at IS NULL
                ) THEN
                    RAISE EXCEPTION 'Document type id "%" not found',
                        doc ->> 'id'
                        USING ERRCODE = 'T2QZ3';
                END IF;

                INSERT INTO provider_qualifications.document_type_category (
                    document_type_id,
                    category_id,
                    required,
                    created_at,
                    updated_at
                )
                VALUES (
                           (doc ->> 'id')::BIGINT,
                           new_category_id,
                           COALESCE((doc ->> 'required')::BOOLEAN, FALSE),
                           NOW(),
                           NOW()
                       );
            END LOOP;
    END IF;

    RETURN new_category_id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.check_postal_code(p_country text, p_postal_code text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF p_country = 'IT' AND p_postal_code !~ '^\d{5}$' THEN
        RAISE EXCEPTION 'Invalid postal code % for country IT', p_postal_code USING ERRCODE = 'T8JZ3';
    END IF;
    IF p_country = 'US' AND p_postal_code !~ '^\d{5}(-\d{4})?$' THEN
        RAISE EXCEPTION 'Invalid postal code % for country US', p_postal_code USING ERRCODE = 'T8JZ3';
    END IF;
    IF p_country = 'FR' AND p_postal_code !~ '^(0[1-9]|[1-8][0-9]|9[0-5]|2A|2B)\d{3}$' THEN
        RAISE EXCEPTION 'Invalid postal code % for country FR', p_postal_code USING ERRCODE = 'T8JZ3';
    END IF;
    IF p_country = 'DE' AND p_postal_code !~ '^\d{5}$' THEN
        RAISE EXCEPTION 'Invalid postal code % for country DE', p_postal_code USING ERRCODE = 'T8JZ3';
    END IF;
    IF p_country = 'GB' AND p_postal_code !~ '^(GIR 0AA|[A-Z]{1,2}[0-9R][0-9A-Z]? ?[0-9][A-Z]{2})$' THEN
        RAISE EXCEPTION 'Invalid postal code % for country GB', p_postal_code USING ERRCODE = 'T8JZ3';
    END IF;
END;
$function$

