CREATE OR REPLACE FUNCTION provider_qualifications.document_edit(p_document_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _document_id BIGINT;
    _file_id BIGINT;
    _expire_date DATE;
    _updated_id BIGINT;
    _existing_count INT;
BEGIN

    _document_id := (p_document_json->>'document_id')::BIGINT;
    _file_id := (p_document_json->>'file_id')::BIGINT;
    _expire_date := (p_document_json->>'expire_date')::DATE;

    -- Validate document exists
    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.document
    WHERE id = _document_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'Document ID % does not exist', _document_id
            USING ERRCODE = 'T6QZ0';
    END IF;

    -- Validate file exists
    SELECT COUNT(*) INTO _existing_count
    FROM files.file
    WHERE id = _file_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'File ID % does not exist', _file_id
            USING ERRCODE = 'T5QZ0';
    END IF;

    UPDATE provider_qualifications.document
    SET
        file_id = _file_id,
        expire_date = _expire_date,
        updated_at = NOW()
    WHERE id = _document_id
      AND deleted_at IS NULL
    RETURNING id INTO _updated_id;

    RETURN _updated_id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.document_history_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- On UPDATE: save OLD file to history before it gets replaced
    IF TG_OP = 'UPDATE' AND OLD.file_id IS DISTINCT FROM NEW.file_id AND OLD.file_id IS NOT NULL THEN
        PERFORM provider_qualifications.document_history_new(
                json_build_object(
                        'document_id', OLD.id,
                        'file_id', OLD.file_id
                )
        );
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.document_history_new(p_history_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _new_history_id BIGINT;
    _document_id BIGINT;
    _file_id BIGINT;
    _existing_count INT;
BEGIN
    _document_id := (p_history_json->>'document_id')::BIGINT;
    _file_id := (p_history_json->>'file_id')::BIGINT;

    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.document
    WHERE id = _document_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'Document ID % does not exist', _document_id
            USING ERRCODE = 'T6QZ2';
    END IF;

    IF _file_id IS NOT NULL THEN
        SELECT COUNT(*) INTO _existing_count
        FROM files.file
        WHERE id = _file_id
          AND deleted_at IS NULL;

        IF _existing_count = 0 THEN
            RAISE EXCEPTION 'File ID % does not exist', _file_id
                USING ERRCODE = 'T5QZ0';
        END IF;

        -- Check if this document+file combination already exists in history
        SELECT COUNT(*) INTO _existing_count
        FROM provider_qualifications.document_history
        WHERE document_id = _document_id
          AND file_id = _file_id;

        IF _existing_count > 0 THEN
            -- Already in history, silently skip (idempotent)
            RETURN NULL;
        END IF;
    END IF;

    -- Insert history record
    INSERT INTO provider_qualifications.document_history (
        document_id,
        file_id,
        created_at
    )
    VALUES (
               _document_id,
               _file_id,
               NOW()
           )
    RETURNING id INTO _new_history_id;

    RETURN _new_history_id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.document_new(p_document_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _new_document_id BIGINT;
    _existing_count INT;
    _file_id BIGINT;
    _expire_date DATE;
    _provider_id BIGINT;
    _document_type_id BIGINT;
BEGIN
    -- Parse the JSON object into individual fields
    _file_id := (p_document_json->>'file_id')::BIGINT;
    _expire_date := (p_document_json->>'expire_date')::DATE;
    _provider_id := (p_document_json->>'provider_id')::BIGINT;
    _document_type_id := (p_document_json->>'document_type_id')::BIGINT;

    -- Validate file exists
    SELECT COUNT(*) INTO _existing_count
    FROM files.file
    WHERE id = _file_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'File ID % does not exist', _file_id
            USING ERRCODE = 'T4QZ0';
    END IF;

    -- Validate provider exists
    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.provider
    WHERE id = _provider_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'Provider ID % does not exist', _provider_id
            USING ERRCODE = 'T4QZ2';
    END IF;

    -- Validate document type exists
    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.document_type
    WHERE id = _document_type_id
      AND deleted_at IS NULL;

    IF _existing_count = 0 THEN
        RAISE EXCEPTION 'Document type ID % does not exist', _document_type_id
            USING ERRCODE = 'T2QZ0';
    END IF;

    -- Optional: Prevent duplicate document (same provider + type)
    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.document
    WHERE provider_id = _provider_id
      AND document_type_id = _document_type_id
      AND deleted_at IS NULL;

    IF _existing_count > 0 THEN
        RAISE EXCEPTION 'Provider % already has a document of type %', _provider_id, _document_type_id
            USING ERRCODE = 'T4QZ1';
    END IF;

    -- Insert new document
    INSERT INTO provider_qualifications.document (
        file_id,
        expire_date,
        provider_id,
        document_type_id,
        state,
        created_at,
        updated_at,
        source
    )
    VALUES (
               _file_id,
               _expire_date,
               _provider_id,
               _document_type_id,
               'OK',
               NOW(),
               NOW(),
            'INTERNAL'
           )
    RETURNING id INTO _new_document_id;

    -- Return the newly created document ID
    RETURN _new_document_id;
END;
$function$

