CREATE OR REPLACE FUNCTION provider_qualifications.document_type_category_updated()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    _provider_record RECORD;
BEGIN
    -- INSERT: new document requirement added
    IF TG_OP = 'INSERT' THEN
        FOR _provider_record IN
            SELECT p.provider_id
            FROM provider_qualifications.provider_category p
            WHERE p.category_id = NEW.category_id
        LOOP
            PERFORM provider_qualifications.calculate_provider_qualification(_provider_record.provider_id);
        END LOOP;

        RETURN NEW;
    END IF;

    -- UPDATE: category changed
    IF TG_OP = 'UPDATE' THEN
        IF OLD.category_id IS DISTINCT FROM NEW.category_id THEN
            -- OLD category
            FOR _provider_record IN
                SELECT p.provider_id
                FROM provider_qualifications.provider_category p
                WHERE p.category_id = OLD.category_id
            LOOP
                PERFORM provider_qualifications.calculate_provider_qualification(_provider_record.provider_id);
            END LOOP;

            -- NEW category
            FOR _provider_record IN
                SELECT p.provider_id
                FROM provider_qualifications.provider_category p
                WHERE p.category_id = NEW.category_id
            LOOP
                PERFORM provider_qualifications.calculate_provider_qualification(_provider_record.provider_id);
            END LOOP;

            RETURN NEW;
        END IF;

        -- Same category, requirements changed
        FOR _provider_record IN
            SELECT p.provider_id
            FROM provider_qualifications.provider_category p
            WHERE p.category_id = NEW.category_id
        LOOP
            PERFORM provider_qualifications.calculate_provider_qualification(_provider_record.provider_id);
        END LOOP;
    END IF;

    -- DELETE: document requirement removed
    IF TG_OP = 'DELETE' THEN
        FOR _provider_record IN
            SELECT p.provider_id
            FROM provider_qualifications.provider_category p
            WHERE p.category_id = OLD.category_id
        LOOP
            PERFORM provider_qualifications.calculate_provider_qualification(_provider_record.provider_id);
        END LOOP;

        RETURN OLD;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.document_type_edit(p_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    doc_id BIGINT;
    doc_name TEXT;
    existing_count INT;
BEGIN
    -- Extract ID and name from JSON
    doc_id := (p_json::jsonb ->> 'id')::BIGINT;
    doc_name := p_json::jsonb ->> 'name';

    -- Validate that ID exists
    IF doc_id IS NULL THEN
        RAISE EXCEPTION 'Document type ID (id) is required'
            USING ERRCODE = 'T2QZ3';
    END IF;

    -- Validate that name exists and is not empty
    IF doc_name IS NULL OR doc_name = '' THEN
        RAISE EXCEPTION 'Document type name (name) is required and cannot be empty'
            USING ERRCODE = 'T2QZ3';
    END IF;

    -- Check if another document type with the same name already exists (not deleted)
    SELECT COUNT(*) INTO existing_count
    FROM provider_qualifications.document_type
    WHERE name = doc_name
      AND deleted_at IS NULL
      AND id <> doc_id;

    IF existing_count > 0 THEN
        RAISE EXCEPTION 'Document type "%" already exists', doc_name
            USING ERRCODE = 'T2QZ1';
    END IF;

    -- Update the document type
    UPDATE provider_qualifications.document_type
    SET name = doc_name,
        updated_at = NOW()
    WHERE id = doc_id
      AND deleted_at IS NULL;

    RETURN doc_id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.document_type_new(p_json json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _new_document_type_id BIGINT;
    _existing_count INT;
BEGIN
    -- Validate that "name" exists and is not empty
    IF NOT (p_json::jsonb ? 'name') OR (p_json::jsonb ->> 'name') = '' THEN
        RAISE EXCEPTION 'Document type name (name) is required and cannot be empty'
            USING ERRCODE = 'T2QZ3';
    END IF;

    -- Check if a document type with the same name already exists (not deleted)
    SELECT COUNT(*) INTO _existing_count
    FROM provider_qualifications.document_type
    WHERE name = (p_json::jsonb ->> 'name')
      AND deleted_at IS NULL;

    IF _existing_count > 0 THEN
        RAISE EXCEPTION 'Document type "%" already exists', (p_json::jsonb ->> 'name')
            USING ERRCODE = 'T2QZ1';
    END IF;

    -- Insert the new document type
    INSERT INTO provider_qualifications.document_type (name, created_at, updated_at)
    VALUES (p_json::jsonb ->> 'name', NOW(), NOW())
    RETURNING id INTO _new_document_type_id;

    RETURN _new_document_type_id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.fix_document_state_by_expiry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- New NON-INTERNAL documents -> always set to PENDING_VERIFY_ALL
    IF NEW.source <> 'INTERNAL' THEN
        NEW.state := 'PENDING_VERIFY_ALL';
        RETURN NEW;
    END IF;

    -- INTERNAL documents
    IF NEW.state = 'EXPIRED'
        AND NEW.expire_date >= CURRENT_DATE
    THEN
        NEW.state := 'OK';
    END IF;

    IF NEW.state = 'OK'
        AND NEW.expire_date < CURRENT_DATE
    THEN
        NEW.state := 'EXPIRED';
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.notification_get_all(_provider_id bigint DEFAULT NULL::bigint, _notification_type text DEFAULT NULL::text, _last_days integer DEFAULT 30)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _result JSON;
    _valid_notification_types TEXT[] := ARRAY[
        'PROVIDER_CATEGORY_STATE_CHANGE',
        'DOCUMENT_EXPIRATION',
        'PROVIDER_DRAFT'
        ];
BEGIN
    IF _last_days IS NOT NULL AND _last_days <= 0 THEN
        RAISE EXCEPTION 'Invalid last_days value: %', _last_days
            USING ERRCODE = 'T7QZ3';
    END IF;

    IF _notification_type IS NOT NULL AND _notification_type <> '' THEN
        IF NOT (_notification_type = ANY (_valid_notification_types)) THEN
            RAISE EXCEPTION 'Notification type not found: %', _notification_type
                USING ERRCODE = 'T7QZ3';
        END IF;
    END IF;

    IF _provider_id IS NOT NULL THEN
        IF NOT EXISTS (
            SELECT 1
            FROM provider_qualifications.provider p
            WHERE p.id = _provider_id AND p.deleted_at IS NULL
        ) THEN
            RAISE EXCEPTION 'Provider ID % not found', _provider_id
                USING ERRCODE = 'T1QZ0';
        END IF;
    END IF;

    REFRESH MATERIALIZED VIEW provider_qualifications.notification;

    SELECT COALESCE(json_agg(n), '[]'::json)
    INTO _result
    FROM provider_qualifications.notification n
    WHERE (_provider_id IS NULL OR n.provider_id = _provider_id)
      AND (_notification_type IS NULL OR _notification_type = '' OR n.notification_type = _notification_type)
      AND (
        -- DOCUMENT_EXPIRATION → expired + next N days
        (
            n.notification_type = 'DOCUMENT_EXPIRATION'
                AND n.event_time <= now() + (_last_days || ' days')::interval
            )
            -- ELSE → past only (generic)
            OR
        (
            n.notification_type <> 'DOCUMENT_EXPIRATION'
                AND n.event_time BETWEEN now() - (_last_days || ' days')::interval
                AND now()
            )
        );

    RETURN _result;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.provider_edit(p_json json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_provider_id BIGINT;
    _old_state TEXT;

    _company_name_var TEXT;
    _vat_number_var   TEXT;
    _cf_var           TEXT;
    _address_var      TEXT;
    _city_var         TEXT;
    _postal_code_var  TEXT;
    _province_var     TEXT;
    _country_var      TEXT;
    _language_var provider_qualifications.language;
    _erp_id_var       BIGINT;
    _state_var        TEXT;
    _first_name_var   TEXT;
    _last_name_var    TEXT;
    _email_var        TEXT;
    _phone_var        TEXT;
    _phone_var_provided BOOLEAN;
    _first_name_var_provided BOOLEAN;
    _last_name_var_provided BOOLEAN;
    _default_payment_method_var TEXT;
    _skip_qualification_validation_var BOOLEAN;
BEGIN
    v_provider_id := (p_json->>'id')::BIGINT;
    IF v_provider_id IS NULL THEN
        RAISE EXCEPTION 'Provider ID is required' USING ERRCODE = 'T8JZ3';
    END IF;

    SELECT state INTO _old_state
    FROM provider_qualifications.provider
    WHERE id = v_provider_id AND deleted_at IS NULL;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Provider with id % not found', v_provider_id USING ERRCODE = 'T1QZ0';
    END IF;

    -- Extract JSON values
    _company_name_var := NULLIF(p_json->>'company_name','');
    _vat_number_var   := NULLIF(p_json->>'vat_number','');
    _cf_var           := NULLIF(p_json->>'cf','');
    _address_var      := NULLIF(p_json->>'address','');
    _city_var         := NULLIF(p_json->>'city','');
    _postal_code_var  := NULLIF(p_json->>'postal_code','');
    _province_var     := NULLIF(p_json->>'province','');
    _country_var      := NULLIF(p_json->>'country','');
    _language_var     := NULLIF(p_json->>'language','')::provider_qualifications.language;
    _state_var        := NULLIF(p_json->>'state','');
    _default_payment_method_var := NULLIF(p_json->>'default_payment_method','');
    _skip_qualification_validation_var := NULLIF(p_json->>'skip_qualification_validation', '')::BOOLEAN;

    -- Validate default_payment_method if provided
    IF _default_payment_method_var IS NOT NULL THEN
        IF NOT EXISTS (
            SELECT 1
            FROM provider_qualifications.payment_method
            WHERE code = _default_payment_method_var
        ) THEN
            RAISE EXCEPTION 'Payment method code "%" does not exist', _default_payment_method_var
                USING ERRCODE = 'T8QZ3';
        END IF;
    END IF;

    -- Handle erp_id
    IF p_json::jsonb ? 'erp_id' AND p_json->>'erp_id' ~ '^\d+$' THEN
        _erp_id_var := (p_json->>'erp_id')::BIGINT;
    ELSE
        _erp_id_var := NULL;
    END IF;

    -- Handle provider_ref
    IF p_json::jsonb ? 'ref' THEN
        _first_name_var := NULLIF(p_json->'ref'->>'first_name','');
        _last_name_var  := NULLIF(p_json->'ref'->>'last_name','');
        _email_var      := NULLIF(p_json->'ref'->>'email','');
        _phone_var      := NULLIF(p_json->'ref'->>'phone','');
        _first_name_var_provided := p_json::jsonb ? 'ref' AND p_json::jsonb->'ref' ? 'first_name';
        _last_name_var_provided  := p_json::jsonb ? 'ref' AND p_json::jsonb->'ref' ? 'last_name';
        _phone_var_provided := p_json::jsonb ? 'ref' AND p_json::jsonb->'ref' ? 'phone';

        IF EXISTS (
            SELECT 1
            FROM provider_qualifications.provider_ref
            WHERE provider_id = v_provider_id
        ) THEN
            UPDATE provider_qualifications.provider_ref
            SET
                first_name = CASE WHEN _first_name_var_provided THEN _first_name_var ELSE first_name END,
                last_name  = CASE WHEN _last_name_var_provided THEN _last_name_var ELSE last_name END,
                email      = COALESCE(_email_var, email),
                phone      = CASE WHEN _phone_var_provided THEN _phone_var ELSE phone END,
                updated_at = NOW()
            WHERE provider_id = v_provider_id;
        ELSE
            INSERT INTO provider_qualifications.provider_ref (
                provider_id,
                first_name,
                last_name,
                email,
                phone,
                created_at,
                updated_at
            )
            VALUES (
                       v_provider_id,
                       _first_name_var,
                       _last_name_var,
                       _email_var,
                       _phone_var,
                       NOW(),
                       NOW()
                   );
        END IF;
    END IF;

    -- Update provider
    UPDATE provider_qualifications.provider
    SET
        company_name = COALESCE(_company_name_var, company_name),
        vat_number   = COALESCE(_vat_number_var, vat_number),
        cf           = COALESCE(_cf_var, cf),
        address      = COALESCE(UPPER(_address_var), address),
        city         = COALESCE(UPPER(_city_var), city),
        postal_code  = COALESCE(_postal_code_var, postal_code),
        province     = COALESCE(_province_var, province),
        country      = COALESCE(_country_var, country),
        language     = COALESCE(_language_var, language),
        default_payment_method = COALESCE(_default_payment_method_var, default_payment_method),
        state        = COALESCE(_state_var, state),
        erp_id       = COALESCE(_erp_id_var, erp_id),
        skip_qualification_validation = COALESCE(_skip_qualification_validation_var, skip_qualification_validation),
        updated_at   = NOW()
    WHERE id = v_provider_id AND deleted_at IS NULL;

    -- Validate leaving DRAFT
    IF _old_state = 'DRAFT'
        AND _state_var IS NOT NULL
        AND _state_var <> 'DRAFT' THEN
        PERFORM provider_qualifications.validate_provider_complete_from_json(
                v_provider_id,
                p_json
                );
    END IF;

END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.provider_ref_delete(_json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
    _existing_type text;
BEGIN
    _id := (_json_data->>'id')::bigint;

    SELECT reference_type INTO _existing_type
    FROM provider_qualifications.provider_ref
    WHERE id = _id;

    IF _existing_type IS NULL THEN
        RAISE EXCEPTION '[provider_ref_delete] Reference % not found', _id
            USING ERRCODE = 'T9QZ0';
    END IF;

    IF _existing_type = 'QUALIFICATION_REF' THEN
        RAISE EXCEPTION '[provider_ref_delete] QUALIFICATION_REF cannot be deleted'
            USING ERRCODE = 'T9QZ3';
    END IF;

    DELETE FROM provider_qualifications.provider_ref WHERE id = _id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.provider_ref_edit(_json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
    _existing_type text;
    _new_type text;
    _phone_var_provided BOOLEAN;
    _first_name_var_provided BOOLEAN;
    _last_name_var_provided BOOLEAN;
BEGIN
    _id := (_json_data->>'id')::bigint;

    SELECT reference_type INTO _existing_type
    FROM provider_qualifications.provider_ref
    WHERE id = _id;

    IF _existing_type IS NULL THEN
        RAISE EXCEPTION '[provider_ref_edit] Reference % not found', _id
            USING ERRCODE = 'T9QZ0';
    END IF;

    IF _existing_type = 'QUALIFICATION_REF' THEN
        RAISE EXCEPTION '[provider_ref_edit] QUALIFICATION_REF cannot be edited'
            USING ERRCODE = 'T9QZ3';
    END IF;

    _new_type := COALESCE(NULLIF(_json_data->>'reference_type', ''), _existing_type);

    IF _new_type = 'QUALIFICATION_REF' THEN
        RAISE EXCEPTION '[provider_ref_edit] Cannot assign QUALIFICATION_REF'
            USING ERRCODE = 'T9QZ3';
    END IF;

    IF (_json_data->>'reference_type') IS NOT NULL AND (_json_data->>'reference_type') != '' THEN
        IF NOT EXISTS (
            SELECT 1 FROM provider_qualifications.provider_reference_type WHERE name = _new_type
        ) THEN
            RAISE EXCEPTION '[provider_ref_edit] reference_type % does not exist', _new_type
                USING ERRCODE = 'T9QZ3';
        END IF;
    END IF;

    _phone_var_provided := _json_data::jsonb ? 'phone';
    _first_name_var_provided := _json_data::jsonb ? 'first_name';
    _last_name_var_provided := _json_data::jsonb ? 'last_name';

    UPDATE provider_qualifications.provider_ref
    SET
        first_name     = CASE WHEN _first_name_var_provided THEN NULLIF(_json_data->>'first_name', '') ELSE first_name END,
        last_name      = CASE WHEN _last_name_var_provided THEN NULLIF(_json_data->>'last_name', '') ELSE last_name END,
        email          = COALESCE(_json_data->>'email', email),
        phone          = CASE WHEN _phone_var_provided THEN NULLIF(_json_data->>'phone', '') ELSE phone END,
        reference_type = _new_type,
        updated_at     = NOW()
    WHERE id = _id;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.provider_ref_new(_json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
    _ref_type text;
    _provider_id bigint;
BEGIN
    _provider_id := (_json_data->>'provider_id')::bigint;
    _ref_type := COALESCE(_json_data->>'reference_type', 'QUALIFICATION_REF');

    IF _ref_type = 'QUALIFICATION_REF' THEN
        RAISE EXCEPTION '[provider_ref_new] QUALIFICATION_REF cannot be created'
            USING ERRCODE = 'T9QZ3';
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM provider_qualifications.provider_reference_type WHERE name = _ref_type
    ) THEN
        RAISE EXCEPTION '[provider_ref_new] reference_type % does not exist', _ref_type
            USING ERRCODE = 'T9QZ3';
    END IF;

    INSERT INTO provider_qualifications.provider_ref (
        provider_id,
        first_name,
        last_name,
        email,
        phone,
        reference_type
    ) VALUES (
                 _provider_id,
                 _json_data->>'first_name',
                 _json_data->>'last_name',
                 _json_data->>'email',
                 _json_data->>'phone',
                 _ref_type
             )
    RETURNING id INTO _id;

    RETURN json_build_object('id', _id);
END;
$function$

