CREATE OR REPLACE FUNCTION provider_qualifications.trg_provider_state_guard()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    old_json jsonb;
    new_json jsonb;
BEGIN

    -- Skip validation if sync_bypass is true
    IF NEW.sync_bypass = TRUE OR (OLD.sync_bypass = TRUE AND NEW.sync_bypass = FALSE) THEN
        RETURN NEW;
    END IF;

    -- Only applies if provider is ACTIVE
    IF OLD.state = 'ACTIVE' THEN

        -- Only allow ACTIVE <-> INACTIVE
        IF NEW.state NOT IN ('ACTIVE','INACTIVE') THEN
            RAISE EXCEPTION
                'Active provider state can only be ACTIVE or INACTIVE'
                USING ERRCODE = 'T8JZ3';
        END IF;

        -- Remove fields ignored in comparison
        old_json := to_jsonb(OLD)
            - ARRAY['state','provider_ref', 'default_payment_method', 'skip_qualification_validation', 'updated_at','created_at','deleted_at'];

        new_json := to_jsonb(NEW)
            - ARRAY['state','provider_ref', 'default_payment_method', 'skip_qualification_validation', 'updated_at','created_at','deleted_at'];

        -- If anything else changes → block it
        IF old_json <> new_json THEN
            RAISE EXCEPTION
                'Cannot modify provider details when state is ACTIVE (except provider_ref)'
                USING ERRCODE = 'T8JZ3';
        END IF;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.trg_validate_provider_by_state()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF TG_OP IN ('INSERT', 'UPDATE')
        AND COALESCE(NEW.state, 'DRAFT') <> 'DRAFT' THEN
        PERFORM provider_qualifications.validate_provider_complete(NEW);
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.uppercase_city()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.country = 'IT' AND NEW.city IS NOT NULL THEN
        NEW.city := UPPER(NEW.city);
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.validate_provider_complete(p provider_qualifications.provider)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _ref_count INT;
BEGIN
    -- Skip validation if sync_bypass is true
    IF p.sync_bypass = TRUE THEN
        RETURN;
    END IF;

    IF p.state <> 'DRAFT' THEN
        IF p.company_name IS NULL OR p.company_name = '' THEN
            RAISE EXCEPTION 'company_name is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.address IS NULL OR p.address = '' THEN
            RAISE EXCEPTION 'address is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.city IS NULL OR p.city = '' THEN
            RAISE EXCEPTION 'city is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.postal_code IS NULL OR p.postal_code = '' THEN
            RAISE EXCEPTION 'postal_code is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.country IS NULL OR p.country = '' THEN
            RAISE EXCEPTION 'country is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.erp_id IS NULL OR p.erp_id = 0 THEN
            RAISE EXCEPTION 'erp_id is required' USING ERRCODE = 'T8JZ3';
        END IF;
        IF p.default_payment_method IS NULL THEN
            RAISE EXCEPTION 'default_payment_method is required' USING ERRCODE = 'T8JZ3';
        END IF;

        SELECT COUNT(*) INTO _ref_count
        FROM provider_qualifications.provider_ref
        WHERE provider_id = p.id;

        IF _ref_count = 0 THEN
            RAISE EXCEPTION 'Active provider must have at least one reference' USING ERRCODE = 'T8JZ3';
        END IF;

        PERFORM provider_qualifications.check_postal_code(p.country, p.postal_code);

        -- removed this from validations since
        --PERFORM provider_qualifications.check_province_by_country(p.country, p.province, p.sync_bypass);
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION provider_qualifications.validate_provider_complete_from_json(p_provider_id bigint, p_json json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _p provider_qualifications.provider%ROWTYPE;
    _ref_count INT;
    _new_state TEXT;
BEGIN

    -- Load current provider from DB
    SELECT * INTO _p
    FROM provider_qualifications.provider
    WHERE id = p_provider_id;

    -- Skip validation if sync_bypass is true
    IF _p.sync_bypass = TRUE THEN
        RETURN;
    END IF;

    -- Determine the effective new state after JSON update
    _new_state := COALESCE(p_json->>'state', _p.state);

    -- Skip validation if the resulting state is still DRAFT
    IF _new_state = 'DRAFT' THEN
        RETURN;
    END IF;

    -- Count existing references
    SELECT COUNT(*) INTO _ref_count
    FROM provider_qualifications.provider_ref
    WHERE provider_id = p_provider_id;

    -- Validate references: either existing in DB OR provided in JSON
    IF _ref_count = 0 AND NOT (
        p_json::jsonb ? 'ref' AND
        jsonb_typeof(p_json::jsonb -> 'ref') = 'object'
        ) THEN
        RAISE EXCEPTION 'Active provider must have at least one reference' USING ERRCODE = 'T8JZ3';
    END IF;

    -- Validate required fields: company_name, address, city, postal_code, country
    IF (_p.company_name IS NULL OR _p.company_name = '') AND
       (p_json->>'company_name' IS NULL OR p_json->>'company_name' = '') THEN
        RAISE EXCEPTION 'company_name is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF (_p.address IS NULL OR _p.address = '') AND
       (p_json->>'address' IS NULL OR p_json->>'address' = '') THEN
        RAISE EXCEPTION 'address is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF (_p.city IS NULL OR _p.city = '') AND
       (p_json->>'city' IS NULL OR p_json->>'city' = '') THEN
        RAISE EXCEPTION 'city is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF (_p.postal_code IS NULL OR _p.postal_code = '') AND
       (p_json->>'postal_code' IS NULL OR p_json->>'postal_code' = '') THEN
        RAISE EXCEPTION 'postal_code is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF (_p.country IS NULL OR _p.country = '') AND
       (p_json->>'country' IS NULL OR p_json->>'country' = '') THEN
        RAISE EXCEPTION 'country is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF (_p.default_payment_method IS NULL OR _p.default_payment_method = '') AND
       (p_json->>'default_payment_method' IS NULL OR p_json->>'default_payment_method' = '') THEN
        RAISE EXCEPTION 'default_payment_method is required' USING ERRCODE = 'T8JZ3';
    END IF;

    IF COALESCE(NULLIF(p_json->>'erp_id', '')::BIGINT, _p.erp_id) IS NULL THEN
        RAISE EXCEPTION 'erp_id is required' USING ERRCODE = 'T8JZ3';
    END IF;

    -- Check postal code validity using effective values
    PERFORM provider_qualifications.check_postal_code(
            COALESCE(p_json->>'country', _p.country),
            COALESCE(p_json->>'postal_code', _p.postal_code)
            );

    -- Check province validity using effective values
    PERFORM provider_qualifications.check_province_by_country(
            COALESCE(p_json->>'country', _p.country),
            COALESCE(p_json->>'province', _p.province),
            _p.sync_bypass
            );

END;
$function$
